adingLeft center\\"][vc_column_text css_animation=\\"fadeInUp\\" css=\\".vc_custom_1733479777586{margin-bottom: 15px !important;}\\"]\\n<h2 class=\\"ts-head-title\\" style=\\"color: #ffffff;\\">How we do</h2>\\n[/vc_column_text][vc_column_text css_animation=\\"fadeInUp\\" css=\\".vc_custom_1733479937785{margin-bottom: 15px !important;}\\" el_class=\\"m_title\\"]\\n<h2 style=\\"font-size: 44px; color: #ffffff; line-height: 1.2; text-transform: none; text-align: center; letter-spacing: 0;\\">What we do</h2>\\n[/vc_column_text][vc_column_text css_animation=\\"fadeInUp\\" css=\\".vc_custom_1733479929424{margin-bottom: 0px !important;}\\" el_class=\\"m_title\\"]\\n<div class=\\"ts-head-description\\" style=\\"; color: #ffffff;\\">Esthetica specializes in the precision manufacturing of high-end spa tables and massage bed ranges, offering a comprehensive range of products tailored for hotel and resort spas. Our cutting-edge manufacturing facility boasts a modern setup. Esthetica handles every aspect of the manufacturing process with meticulous care and expertise. Your vision is our priority, and our capabilities span the entire spectrum of furniture production.</div>\\n[/vc_column_text][/vc_column_inner][/vc_row_inner][vc_row_inner overlay_row=\\"\\" el_class=\\"project-sec\\"][vc_column_inner][wolfe_client_logos autoplay_timeout=\\"5000\\" img_ids=\\"5355,5356,5357,5358,5359,5360,5361,5362,5363,5364,5365,5366,5367,5368,5369,5370,5371,5372,5373,5374,5375,5376,5377,5378,5379,5380,5381,5382,5383,5384,5385,5386,5387,5388,5389,5390,5391,5392,5393\\"][/vc_column_inner][/vc_row_inner][/vc_column][/vc_row][vc_row full_width=\\"stretch_row\\" equal_height=\\"yes\\" content_placement=\\"middle\\" overlay_row=\\"\\" el_class=\\"clientsSec\\"][vc_column css=\\".vc_custom_1465560529987{padding-bottom: 40px !important;}\\" el_class=\\"headingLeft center\\"][vc_column_text css_animation=\\"fadeInUp\\" css=\\".vc_custom_1733480150230{margin-bottom: 15px !important;}\\" el_class=\\"m_titl