cmq9m1lxm0000cgsywxz5slmy	testimonials	{"google": {"apiKey": "AIzaSyAaHkvRNEtxCOMQMnRy6_ulVfUIPViC3Ms", "enabled": true, "placeId": "ChIJQQAAwNA9DTkR7LYKkcuY894", "minRating": 1}, "source": "google", "section": {"title": "Testimonials", "enabled": true, "subtitle": ""}, "carousel": {"loop": true, "speed": 600, "enabled": true, "autoplay": true, "spaceBetween": 8, "slidesPerView": {"lg": 3, "md": 2, "sm": 1}, "showNavigation": true, "autoplayDelayMs": 5000}, "displayCount": 10, "manualReviews": [{"id": "1", "body": "Nice Products and Good Range available!", "rating": 5, "source": "manual", "authorName": "NN", "publishedAt": "2025-06-16"}, {"id": "2", "body": "I ordered the Akriti Model, and it is very comfortable, Thanks to Aman for given me clear and amazing description for this product i am highly satisfied with this product.😊😊", "rating": 5, "source": "manual", "avatarUrl": "https://lh3.googleusercontent.com/a-/ALV-UjVDwHSH3tZYH31qUuAOI12ovOAf-Dr7Mkv2E1EcUY3PKv5yZnWcKw=w40-h40-c-rp-mo-ba2-br100", "authorName": "Jyotsna Vashisht", "publishedAt": "2025-05-02"}, {"id": "4", "body": "Nice product..Good finishing, export quality made in India product…", "rating": 5, "source": "manual", "avatarUrl": "https://lh3.googleusercontent.com/a-/ALV-UjU-l1cJSZYwc0s-3Uc-Dk45DbrAZ1VbnPslX3cYFD6yNZOmga6T=w40-h40-c-rp-mo-ba3-br100", "authorName": "Pinki Singh", "publishedAt": "2025-03-09"}, {"id": "5", "body": "We bought Spa Furniture from SpaEsthetica and the items received are amazing and of a very good quality. In terms of customer dealing the team and Bhavya especially has been a great support!", "rating": 5, "source": "manual", "avatarUrl": "https://lh3.googleusercontent.com/a-/ALV-UjW4nIl-LZdwo005UoRtc-s1ebtAWIKoBcSP8uGFFsJpY0fDx5xLAA=w40-h40-c-rp-mo-br100", "authorName": "Saudamini Bassi", "publishedAt": "2025-05-03"}, {"id": "c241dcd5-edcd-4ed0-af02-9646bd089def", "body": "Premium Export Quality product. Happy to be associated with Esthetica.", "rating": 5, "source": "manual", "authorName": "Vikaas Aggarwal", "publishedAt": "2025-04-22"}, {"id": "722442a7-df33-41d9-941f-278504e3f0c7", "body": "We are a luxury Spa at South Mumbai. We ordered Shirodhara bed from Esthetica. The craftsmanship and the products are excellent, durable and aesthically appealing. We received all accessories and components even prior the promised delivery date. The packing of these products were too of very high standards to eliminate possibility of damages. Above all, Ms Roli had been a wonderful and highly professional Sales Manager who explained us all aspects of the products and provided a factory tour over video call that reaffirmed our trust in the brand. These premium products are highly recommended for any Spa and Salon. All the best Esthetica.", "rating": 5, "source": "manual", "authorName": "Dinesh Rana", "publishedAt": "2025-04-21"}, {"id": "f08bea71-9dbc-4705-8fe1-005c80d11cbc", "body": "We would like say heartfelt thank you to Esthetica and especially Mohini for helping us at Arunachala Rejuvenation Centre based in Ireland, Co. Laois to create needed atmosphere with furniture and special equipment from their range, bringing little part of India to Ireland . Mohini has been very professional throughout the time we had dealings with her, timely communication and great expertise. We were delighted to see the truck arriving with 5 sets of Ayurvedic equipment, it reminded me of buying a new phone and what they say about unboxing it. The unboxing experience of the packaging that the equipment was in, was delightful experience from unscrewing the plywood encased equipment. Everything arrived in beautiful condition and it was lovely to open up packaging of Ayurvedic Puja Thali set, ancillary stool and steps to the excellently crafted treatment table. Thank you to all at Esthetica.", "rating": 5, "source": "manual", "authorName": "Arunachala Laois", "publishedAt": "2025-04-20"}, {"id": "eadbc0d7-3682-4c91-a109-ee2d6dd2779d", "body": " bought two products from this company for my Nail Spa as a small entrepreneur, a MANICURE-PEDICURE CHAIR For SPA pedicure service, and a SHIRODHARA MASSAGE BED in a set.\\nI am satisfied with everything so much, including communication, helpfulness, and customer service. I have to say that when the furniture arrived, I couldn't believe my eyes, really, it is much more beautiful in person than on the web, it was made in very vers high quality, precise work, the edges, the curves, the stitching, everything, it creates a feeling of luxury in a person as he touches the furniture, the touch and smell of the wood materials affect several of our senses at once, the design is clean and elegant, and the furniture is extra comfortable!! All my guests praised the furniture (all of them) I can only recommend it! wonderful beautiful furniture in high quality!!! THANK YOU Esthetica ❤️🙏🏻", "rating": 5, "source": "manual", "avatarUrl": "https://lh3.googleusercontent.com/a-/ALV-UjWKwJja6g7UVqevEmlD4n7Ul2hAy8qYvmKTxTAd6CDYvX-winA2=w40-h40-c-rp-mo-br100", "authorName": "Márta Bodogán", "publishedAt": "2025-02-24"}, {"id": "ceb0ddf2-a451-4424-bfc2-e3b43dce75a0", "body": "Very good derma chair , quality is excellent and looks luxury\\n", "rating": 5, "source": "manual", "avatarUrl": "https://lh3.googleusercontent.com/a-/ALV-UjXQIZYAQ3Qn-oS64Os-7p6K8NNh-edfKQ5wWiZKAAWAb38hU5bC=w40-h40-c-rp-mo-br100", "authorName": "Dr. Rahul Abhishek", "publishedAt": "2025-02-21"}]}	2026-06-18 06:27:55.007
